<x-inventory.layout title="Kategori Barang"><form class="card card-body grid gap-3 md:grid-cols-4"><input name="q" value="{{ request('q') }}" placeholder="Cari kode/nama"><button class="btn btn-primary">Cari</button></form><form method="post" action="{{ route('inventory.categories.store') }}" class="card card-body grid gap-3 md:grid-cols-4">@csrf<input name="code" required placeholder="Kode"><input name="name" required placeholder="Nama kategori"><input name="description" placeholder="Deskripsi"><label><input type="checkbox" name="is_active" value="1" checked> Aktif</label><button class="btn btn-primary" data-disable-on-submit>Simpan</button></form><div class="overflow-x-auto card"><table class="min-w-full text-sm"><tr><th>Kode</th><th>Nama</th><th>Jumlah Barang</th><th>Status</th><th>Aksi</th></tr>@foreach($categories as $c)<tr class="border-t"><td>{{ $c->code }}</td><td>{{ $c->name }}</td><td>{{ $c->items_count }}</td><td>{{ $c->is_active?'Aktif':'Nonaktif' }}</td><td><form method="post" action="{{ route('inventory.categories.update',$c) }}" class="flex gap-2">@csrf @method('put')<input name="code" value="{{ $c->code }}"><input name="name" value="{{ $c->name }}"><input type="hidden" name="is_active" value="0"><label><input type="checkbox" name="is_active" value="1" @checked($c->is_active)> Aktif</label><button class="btn btn-secondary">Update</button></form></td></tr>@endforeach</table>{{ $categories->links() }}</div></x-inventory.layout>
